SELECT feature, description
FROM requirements
WHERE priority > 5 AND status = 'Active';

SELECT requirement_id, created_at, location, feature 
FROM requirements 
WHERE updated_by = 1;

SELECT requirement_id, feature, pass_fail_criteria
FROM requirements
ORDER BY requirement_id ASC;

SELECT cd.coverage_id, cd.requirement_id, cd.coverage_percentage, cd.verified_by, tc.test_case_description
FROM coverage_data cd
INNER JOIN test_cases tc ON cd.requirement_id = tc.requirement_id;

SELECT user_name 
FROM users 
WHERE user_name NOT IN (
    SELECT verified_by 
    FROM verification_results
);

SELECT feature, sub_feature, status
FROM requirements
ORDER BY priority DESC;

SELECT COUNT(*)
FROM requirements
WHERE requirement_id NOT IN (
    SELECT DISTINCT requirement_id
    FROM verification_results
);
